import Foundationstruct NASANeoResponse: Codable {    let nearEarthObjects: [String: [NearEarthObject]]    enum CodingKeys: String, CodingKey {        case nearEarthObjects = "near_earth_objects"    }}struct NearEarthObject: Codable, Identifiable {    let id: String    let name: String    let nasaJplUrl: String    let absoluteMagnitudeH: Double    let estimatedDiameter: EstimatedDiameter    let isPotentiallyHazardousAsteroid: Bool    let closeApproachData: [CloseApproachData]    enum CodingKeys: String, CodingKey {        case id        case name        case nasaJplUrl = "nasa_jpl_url"        case absoluteMagnitudeH = "absolute_magnitude_h"        case estimatedDiameter = "estimated_diameter"        case isPotentiallyHazardousAsteroid = "is_potentially_hazardous_asteroid"        case closeApproachData = "close_approach_data"    }    var cleanName: String {        name.trimmingCharacters(in: .whitespaces)            .replacingOccurrences(of: "(", with: "")            .replacingOccurrences(of: ")", with: "")    }    var diameterMetersMin: Double {        estimatedDiameter.meters.estimatedDiameterMin    }    var diameterMetersMax: Double {        estimatedDiameter.meters.estimatedDiameterMax    }    var firstCloseApproach: CloseApproachData? {        closeApproachData.first    }}struct EstimatedDiameter: Codable {    let meters: DiameterRange}struct DiameterRange: Codable {    let estimatedDiameterMin: Double    let estimatedDiameterMax: Double    enum CodingKeys: String, CodingKey {        case estimatedDiameterMin = "estimated_diameter_min"        case estimatedDiameterMax = "estimated_diameter_max"    }}struct CloseApproachData: Codable {    let closeApproachDate: String    let relativeVelocity: RelativeVelocity    let missDistance: MissDistance    let orbitingBody: String    enum CodingKeys: String, CodingKey {        case closeApproachDate = "close_approach_date"        case relativeVelocity = "relative_velocity"        case missDistance = "miss_distance"        case orbitingBody = "orbiting_body"    }}struct RelativeVelocity: Codable {    let kilometersPerHour: String    enum CodingKeys: String, CodingKey {        case kilometersPerHour = "kilometers_per_hour"    }    var formattedKmH: String {        if let value = Double(kilometersPerHour) {            return String(format: "%.0f km/h", value)        }        return kilometersPerHour    }}struct MissDistance: Codable {    let kilometers: String    let lunar: String    var formattedKm: String {        if let value = Double(kilometers) {            let millions = value / 1_000_000            return String(format: "%.2f million km", millions)        }        return kilometers    }    var formattedLunar: String {        if let value = Double(lunar) {            return String(format: "%.1f lunar distances", value)        }        return lunar    }}